import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Plus, Minus, Search, HelpCircle } from 'lucide-react';
import Footer from '../components/Footer';

const FAQs = () => {
    const [searchQuery, setSearchQuery] = useState('');
    const [openIndex, setOpenIndex] = useState(0);

    const faqs = [
        {
            category: 'Booking & Reservations',
            questions: [
                {
                    q: 'How do I modify or cancel my reservation?',
                    a: 'You can modify or cancel your booking through the "My Bookings" section in your Dashboard up to 48 hours before your check-in date without penalty. For late cancellations, please review our Booking Policy.'
                },
                {
                    q: 'Can I request early check-in or late check-out?',
                    a: 'Early check-in and late check-out are subject to availability. You can request these services during the booking process or by contacting your dedicated property concierge 24 hours prior to arrival.'
                },
                {
                    q: 'Do you require a deposit at booking?',
                    a: 'Yes, a 50% deposit is required to confirm your reservation. The remaining balance can be settled 7 days prior to arrival or at the property depending on your membership tier.'
                }
            ]
        },
        {
            category: 'Stay Experience & Amenities',
            questions: [
                {
                    q: 'Are your heritage properties accessible for guests with disabilities?',
                    a: 'While many of our historical palaces have architectural limitations, we have specially retrofitted ground-floor premium suites in 80% of our properties to ensure accessibility. Please inform us of your needs during booking.'
                },
                {
                    q: 'Do you arrange airport transfers?',
                    a: 'Absolutely. Complimentary luxury airport transfers (Mercedes Benz E-Class or equivalent) are included for all Platinum members and guests booking Presidential Suites.'
                },
                {
                    q: 'Are pets allowed at StayIndia properties?',
                    a: 'Select properties in our Nature and Beach collections are pet-friendly. Heritage palaces generally do not permit pets to preserve historical artifacts. Please look for the "Pet-Friendly" tag when searching.'
                }
            ]
        },
        {
            category: 'Memberships & Rewards',
            questions: [
                {
                    q: 'How do I earn StayIndia Loyalty Points?',
                    a: 'Points are earned on every eligible booking made directly through our website or app. Gold members earn 10 points per 1,000 INR spent, while Platinum members earn 15 points.'
                },
                {
                    q: 'Do loyalty points expire?',
                    a: 'Points remain valid as long as you maintain active account status (at least one booking every 24 months). If no activity occurs, points expire on the 25th month.'
                }
            ]
        }
    ];

    return (
        <div className="bg-[#2a2119] min-h-screen text-[#FDFBF7] font-sans selection:bg-[#EF6C00]">
            <div className="pt-24 pb-16 px-4 sm:px-6 lg:px-8 max-w-[1000px] mx-auto">
                <div className="text-center mb-16">
                    <motion.div
                        initial={{ scale: 0 }}
                        animate={{ scale: 1 }}
                        className="w-16 h-16 bg-[#EF6C00]/20 rounded-full flex items-center justify-center mx-auto mb-6 text-[#EF6C00]"
                    >
                        <HelpCircle size={32} />
                    </motion.div>
                    <h1 className="text-4xl md:text-5xl font-bold mb-6">Frequently Asked Questions</h1>
                    <p className="text-lg text-gray-300 mb-10 max-w-2xl mx-auto">
                        Find answers to common questions about your luxury stay, memberships, and policies.
                    </p>

                    <div className="relative max-w-xl mx-auto">
                        <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400" size={20} />
                        <input
                            type="text"
                            placeholder="Start typing your question..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full bg-[#15100B] border border-[#3b2d22] text-[#FDFBF7] py-4 pl-12 pr-4 rounded-xl focus:outline-none focus:border-[#EF6C00] shadow-xl"
                        />
                    </div>
                </div>

                <div className="space-y-12">
                    {faqs.map((group, groupIdx) => (
                        <div key={groupIdx}>
                            <h2 className="text-2xl font-bold mb-6 text-[#EF6C00] border-b border-[#3b2d22] pb-4">{group.category}</h2>
                            <div className="space-y-4">
                                {group.questions.map((faq, faqIdx) => {
                                    const globalIndex = groupIdx * 100 + faqIdx; // simple unique key generator
                                    const isOpen = openIndex === globalIndex;

                                    if (searchQuery && !faq.q.toLowerCase().includes(searchQuery.toLowerCase()) && !faq.a.toLowerCase().includes(searchQuery.toLowerCase())) {
                                        return null;
                                    }

                                    return (
                                        <div
                                            key={faqIdx}
                                            className="bg-[#1f1812] border border-[#3b2d22] rounded-xl overflow-hidden transition-colors"
                                        >
                                            <button
                                                className="w-full text-left px-6 py-5 flex justify-between items-center hover:bg-[#15100B] transition"
                                                onClick={() => setOpenIndex(isOpen ? null : globalIndex)}
                                            >
                                                <span className="font-semibold pr-8 text-lg">{faq.q}</span>
                                                <div className="flex-shrink-0 text-[#EF6C00]">
                                                    {isOpen ? <Minus size={20} /> : <Plus size={20} />}
                                                </div>
                                            </button>
                                            <AnimatePresence>
                                                {isOpen && (
                                                    <motion.div
                                                        initial={{ height: 0, opacity: 0 }}
                                                        animate={{ height: 'auto', opacity: 1 }}
                                                        exit={{ height: 0, opacity: 0 }}
                                                        className="overflow-hidden"
                                                    >
                                                        <div className="px-6 pb-6 pt-2 text-gray-400 leading-relaxed">
                                                            {faq.a}
                                                        </div>
                                                    </motion.div>
                                                )}
                                            </AnimatePresence>
                                        </div>
                                    );
                                })}
                            </div>
                        </div>
                    ))}
                </div>

                <div className="mt-20 bg-gradient-to-r from-[#1f1812] to-[#15100B] p-10 rounded-2xl border border-[#3b2d22] text-center">
                    <h3 className="text-2xl font-bold mb-4">Still need help?</h3>
                    <p className="text-gray-400 mb-8 max-w-lg mx-auto">Our dedicated luxury concierge team is available 24/7 to assist you with any custom requests or inquiries.</p>
                    <a href="/support" className="inline-block bg-[#EF6C00] hover:bg-[#fb8c00] text-[#15100B] font-bold px-8 py-3 rounded-lg transition-colors">
                        Contact Support
                    </a>
                </div>
            </div>
            <Footer />
        </div>
    );
};

export default FAQs;

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Star, Heart, Share, MapPin, Award, Shield, Wifi, Car, Tv, Wind, CheckCircle } from 'lucide-react';
import axiosClient from '../api/axiosClient';
import { toast } from 'react-toastify';
import { motion } from 'framer-motion';
import useAuthStore from '../store/useAuthStore';

const FlatDetails = () => {
    const { id } = useParams();
    const [flat, setFlat] = useState(null);
    const [loading, setLoading] = useState(true);
    const { isAuthenticated } = useAuthStore();
    const [checkIn, setCheckIn] = useState('');
    const [checkOut, setCheckOut] = useState('');
    const [guests, setGuests] = useState(1);

    // Fallback Mock Data for UI presentation
    const mockFlatData = {
        _id: id,
        title: 'Luxury Penthouse with Skyline View',
        bhk: '3BHK',
        areaSquareFeet: 2500,
        furnishedStatus: 'Fully-Furnished',
        rent: 250, // per night
        rating: 4.96,
        reviews: 128,
        status: 'Available',
        tower: { name: 'Elysium Tower' },
        images: [
            'https://images.unsplash.com/photo-1522708323590-d24dbb6b0267?ixlib=rb-4.0.3&auto=format&fit=crop&w=1200&q=80',
            'https://images.unsplash.com/photo-1502672260266-1c1e5250base?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80',
            'https://images.unsplash.com/photo-1493809842364-78817add7ffb?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80',
            'https://images.unsplash.com/photo-1560448204-e02f11c3d0e2?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80',
            'https://images.unsplash.com/photo-1484154218962-a197022b5858?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80'
        ]
    };

    useEffect(() => {
        const fetchFlat = async () => {
            try {
                const res = await axiosClient.get(`/flats/${id}`);
                setFlat(res.data.data);
            } catch {
                // Fallback to mock data if no db connected
                setFlat(mockFlatData);
            }
            setLoading(false);
        };
        fetchFlat();
    }, [id]);

    const handleReserve = async () => {
        if (!isAuthenticated) return toast.info('Please log in to reserve');
        if (!checkIn) return toast.error('Check-in date is required');
        // Redirect to checkout page with checkout flow instead of directly creating booking
        navigate(`/checkout/${id}`);
    };

    if (loading) return <div className="h-screen w-full flex items-center justify-center">Loading...</div>;

    return (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="max-w-[1120px] mx-auto px-4 sm:px-8 py-6 pb-20"
        >
            {/* Title Area */}
            <h1 className="text-[26px] font-semibold text-gray-900 mb-2">
                {flat.title || `${flat.bhk} Premium Apartment in ${flat.tower?.name}`}
            </h1>
            <div className="flex justify-between items-end mb-6">
                <div className="flex gap-4 items-center text-sm font-semibold underline text-gray-900">
                    <span className="flex items-center gap-1"><Star size={14} className="fill-current" /> {flat.rating || 4.9} · {flat.reviews || 84} reviews</span>
                    <span className="flex items-center gap-1"><Award size={14} /> Superhost</span>
                    <span className="flex items-center gap-1"><MapPin size={14} /> {flat.tower?.name || 'Vasant Vihar'}</span>
                </div>
                <div className="flex gap-4 items-center text-sm font-semibold underline">
                    <button className="flex items-center gap-2 hover:bg-gray-100 p-2 rounded-lg transition"><Share size={16} /> Share</button>
                    <button className="flex items-center gap-2 hover:bg-gray-100 p-2 rounded-lg transition"><Heart size={16} /> Save</button>
                </div>
            </div>

            {/* Image Gallery */}
            <div className="grid grid-cols-4 grid-rows-2 gap-2 h-[400px] md:h-[500px] rounded-2xl overflow-hidden cursor-pointer relative">
                <div className="col-span-4 md:col-span-2 row-span-2">
                    <img src={flat.images?.[0] || mockFlatData.images[0]} className="w-full h-full object-cover hover:opacity-95 transition" alt="Main" />
                </div>
                <div className="hidden md:block col-span-1 row-span-1"><img src={flat.images?.[1] || mockFlatData.images[1]} className="w-full h-full object-cover hover:opacity-95 transition" /></div>
                <div className="hidden md:block col-span-1 row-span-1"><img src={flat.images?.[2] || mockFlatData.images[2]} className="w-full h-full object-cover hover:opacity-95 transition" /></div>
                <div className="hidden md:block col-span-1 row-span-1"><img src={flat.images?.[3] || mockFlatData.images[3]} className="w-full h-full object-cover hover:opacity-95 transition" /></div>
                <div className="hidden md:block col-span-1 row-span-1"><img src={flat.images?.[4] || mockFlatData.images[4]} className="w-full h-full object-cover hover:opacity-95 transition" /></div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-12 mt-12">

                {/* Main Content */}
                <div className="lg:col-span-2">
                    {/* Host Info */}
                    <div className="flex justify-between pb-6 border-b border-gray-200">
                        <div>
                            <h2 className="text-[22px] font-semibold">Entire rental unit hosted by Manager</h2>
                            <p className="text-gray-900 mt-1">{formateGuests(guests)} · {flat.bhk} · {flat.furnishedStatus}</p>
                        </div>
                        <img src="https://ui-avatars.com/api/?name=Host&rounded=true&background=random" alt="Host" className="w-14 h-14" />
                    </div>

                    <div className="py-8 border-b border-gray-200 flex flex-col gap-6">
                        <div className="flex gap-4 items-start">
                            <Award className="w-8 h-8" />
                            <div>
                                <h3 className="font-semibold text-gray-900">Superhost</h3>
                                <p className="text-gray-500 text-sm">Superhosts are experienced, highly rated hosts.</p>
                            </div>
                        </div>
                        <div className="flex gap-4 items-start">
                            <MapPin className="w-8 h-8" />
                            <div>
                                <h3 className="font-semibold text-gray-900">Great location</h3>
                                <p className="text-gray-500 text-sm">95% of recent guests gave the location a 5-star rating.</p>
                            </div>
                        </div>
                    </div>

                    <div className="py-8 border-b border-gray-200">
                        <img src="https://a0.muscache.com/im/pictures/54e427bb-9cb7-4a81-94cf-78f19156faad.jpg" className="h-6 mb-4" alt="AirCover" />
                        <p className="text-gray-900 leading-relaxed mb-4">
                            Every booking includes free protection from Host cancellations, listing inaccuracies, and other issues like trouble checking in.
                        </p>
                        <span className="font-semibold underline cursor-pointer">Learn more</span>
                    </div>

                    <div className="py-8 border-b border-gray-200">
                        <h2 className="text-[22px] font-semibold mb-6">What this place offers</h2>
                        <div className="grid grid-cols-2 gap-4">
                            <div className="flex gap-4 items-center text-gray-700 pb-2"><Wifi /> Fast wifi</div>
                            <div className="flex gap-4 items-center text-gray-700 pb-2"><Car /> Free parking</div>
                            <div className="flex gap-4 items-center text-gray-700 pb-2"><Tv /> 4K TV</div>
                            <div className="flex gap-4 items-center text-gray-700 pb-2"><Wind /> Air conditioning</div>
                        </div>
                    </div>
                </div>

                {/* Sidebar Booking Card */}
                <div className="hidden lg:block">
                    <div className="border border-gray-200 rounded-xl p-6 shadow-xl sticky top-28 bg-white">
                        <div className="flex items-end justify-between mb-6">
                            <div className="flex items-baseline gap-1">
                                <span className="text-[22px] font-semibold">${flat.rent || 150}</span>
                                <span className="text-gray-900 text-sm">night</span>
                            </div>
                            <span className="text-sm font-semibold underline">{flat.reviews || 84} reviews</span>
                        </div>

                        <div className="border border-gray-300 rounded-xl mb-4 overflow-hidden">
                            <div className="flex border-b border-gray-300">
                                <div className="w-1/2 p-3 border-r border-gray-300 uppercase text-[10px] font-bold text-gray-800">
                                    <label>Check-in</label>
                                    <input type="date" value={checkIn} onChange={e => setCheckIn(e.target.value)} className="w-full outline-none text-sm font-normal mt-1" />
                                </div>
                                <div className="w-1/2 p-3 uppercase text-[10px] font-bold text-gray-800">
                                    <label>Checkout</label>
                                    <input type="date" value={checkOut} onChange={e => setCheckOut(e.target.value)} className="w-full outline-none text-sm font-normal mt-1" />
                                </div>
                            </div>
                            <div className="p-3 uppercase text-[10px] font-bold text-gray-800">
                                <label>Guests</label>
                                <select value={guests} onChange={e => setGuests(parseInt(e.target.value))} className="w-full outline-none text-sm font-normal mt-1 bg-transparent">
                                    <option value={1}>1 guest</option>
                                    <option value={2}>2 guests</option>
                                    <option value={3}>3 guests</option>
                                    <option value={4}>4 guests</option>
                                </select>
                            </div>
                        </div>

                        <button
                            onClick={handleReserve}
                            className="w-full bg-[#E31C5F] hover:bg-[#FF385C] text-white rounded-lg py-3 font-semibold text-lg transition shadow-md"
                        >
                            Reserve
                        </button>
                        <p className="text-center text-sm text-gray-500 mt-4">You won't be charged yet</p>

                        {checkIn && checkOut && (
                            <div className="mt-6 flex flex-col gap-3 text-gray-900 border-t border-gray-200 pt-4">
                                <div className="flex justify-between">
                                    <span className="underline">${flat.rent || 150} x 5 nights</span>
                                    <span>${(flat.rent || 150) * 5}</span>
                                </div>
                                <div className="flex justify-between">
                                    <span className="underline">Cleaning fee</span>
                                    <span>$80</span>
                                </div>
                                <div className="flex justify-between">
                                    <span className="underline">Service fee</span>
                                    <span>$120</span>
                                </div>
                                <hr className="my-2 border-gray-300" />
                                <div className="flex justify-between font-bold text-lg">
                                    <span>Total</span>
                                    <span>${((flat.rent || 150) * 5) + 200}</span>
                                </div>
                            </div>
                        )}
                    </div>
                </div>

            </div>
        </motion.div>
    );
};

const formateGuests = (g) => `${g} guest${g > 1 ? 's' : ''}`;

export default FlatDetails;

